class Solution:
    def minimumBoxes(self, apple, capacity):
        total = sum(apple)
        caps = sorted(capacity, reverse=True)
        acc = 0
        for i, c in enumerate(caps):
            acc += c
            if acc >= total:
                return i + 1
        return len(caps)

