var minimumBoxes = function(apple, capacity) {
    const total = apple.reduce((s, x) => s + x, 0);
    capacity.sort((a, b) => b - a);
    let acc = 0;
    for (let i = 0; i < capacity.length; i++) {
        acc += capacity[i];
        if (acc >= total) return i + 1;
    }
    return capacity.length;
};
